// Light decision/log node: flag whether the repo rate moved since last run
const c = $json;
return [{ json: Object.assign({}, c, {
  rate_changed: Number(c.current_repo_rate) !== Number(c.previous_repo_rate)
}) }];

// ===== CONFIG — adjust to taste =====
const PREPAY_STRATEGY = 'one_emi'; // 'one_emi' | 'percent' | 'fixed'
const PREPAY_PERCENT  = 0.05;      // used if 'percent' (5% of outstanding)
const PREPAY_FIXED    = 25000;     // used if 'fixed'

// Indian currency formatting (math is done here; the LLM only writes copy)
function inr(n) {
  n = Math.round(Number(n) || 0);
  return '\u20B9' + n.toLocaleString('en-IN');
}
function inrLakh(n) {
  const l = (Number(n) || 0) / 100000;
  return '\u20B9' + l.toFixed(2) + ' L';
}

// Rate context from the "Get Repo Rate" node (rate_config table)
const cfg = ($('Get Repo Rate').first() || { json: {} }).json || {};
const currentRate = Number(cfg.current_repo_rate);
const prevRate    = Number(cfg.previous_repo_rate);
const rateChanged = isFinite(currentRate) && isFinite(prevRate) && currentRate !== prevRate;
const rateDirection = rateChanged ? (currentRate > prevRate ? 'increased' : 'decreased') : 'unchanged';

// This loan (one item)
const loan  = $input.item.json;
const P      = Number(loan.outstanding_principal);
const annual = Number(loan.annual_rate); // % per annum, e.g. 8.5
const EMI    = Number(loan.emi);
const i      = annual / 12 / 100;        // monthly rate

// Remaining months from amortization (used if not supplied)
function months(principal) {
  if (i <= 0) return principal / EMI;
  const ratio = (principal * i) / EMI;
  if (ratio >= 1) return Infinity;       // EMI too small to ever amortize
  return -Math.log(1 - ratio) / Math.log(1 + i);
}
const N = Number(loan.remaining_months) > 0
  ? Number(loan.remaining_months)
  : Math.ceil(months(P));

// Suggested prepayment
let X;
if (PREPAY_STRATEGY === 'percent')      X = P * PREPAY_PERCENT;
else if (PREPAY_STRATEGY === 'fixed')   X = PREPAY_FIXED;
else                                    X = EMI;            // one extra EMI
X = Math.max(1000, Math.round(X / 1000) * 1000);           // round to nearest 1000
X = Math.min(X, P);                                        // never exceed outstanding

// Impact of prepaying X now (EMI held constant -> tenure shortens)
const P2 = P - X;
const n2 = Math.ceil(months(P2));
const monthsSaved   = Math.max(0, N - n2);
const interestSaved = Math.max(0, Math.round(EMI * (N - n2) - X));

const facts = {
  name: loan.full_name || 'there',
  outstanding: inr(P),
  suggested_prepayment: inr(X),
  interest_saved: inrLakh(interestSaved),
  months_saved: monthsSaved,
  time_saved: Math.floor(monthsSaved / 12) + 'y ' + (monthsSaved % 12) + 'm',
  repo_rate_status: rateDirection,
  current_repo_rate: isFinite(currentRate) ? currentRate + '%' : 'n/a',
};

const system = [
  'You write short, warm, motivating home-loan prepayment nudges for Indian borrowers using the Unloqs app.',
  'Tone: encouraging, concrete, never pushy or alarmist.',
  'Use ONLY the figures provided — never invent numbers. Keep the Indian formatting (\u20B9, lakhs).',
  'Output ONLY valid JSON: {"subject": string, "message": string}. Message under 90 words.'
].join(' ');

const user = 'Write a prepayment nudge from these facts:\n' + JSON.stringify(facts, null, 2) +
  '\nIf repo_rate_status is "decreased", note that easing rates are a good moment to prepay; ' +
  'if "increased", note prepaying reduces exposure to higher rates; ' +
  'if "unchanged", keep it about momentum and progress.';

const openai_body = {
  model: 'gpt-4o-mini',
  temperature: 0.7,
  response_format: { type: 'json_object' },
  messages: [
    { role: 'system', content: system },
    { role: 'user', content: user }
  ]
};

return {
  json: {
    user_id: loan.user_id,
    email: loan.email,
    phone: loan.phone || null,
    channel: 'email',
    suggested_prepayment: X,
    interest_saved: interestSaved,
    months_saved: monthsSaved,
    rate_changed: rateChanged,
    openai_body
  }
};

let parsed = {};
try {
  parsed = JSON.parse($json.choices[0].message.content);
} catch (e) {
  parsed = {
    subject: 'A smart move on your home loan',
    message: 'A small prepayment this month could shorten your loan and cut interest. Open Unloqs to see your personalised plan.'
  };
}
const src = $('Compute Impact').item.json;
return { json: {
  user_id: src.user_id,
  email: src.email,
  channel: src.channel,
  subject: parsed.subject,
  message: parsed.message,
  suggested_prepayment: src.suggested_prepayment,
  interest_saved: src.interest_saved,
  months_saved: src.months_saved,
  status: 'sent'
}};
